            rotacion.unshift(rotacion.pop());
        }

        const jornadasVuelta = jornadas.map(j =>
            j.map(({ local, visitante }) => ({
                local: visitante,
                visitante: local,
            }))
        );
        return [...jornadas, ...jornadasVuelta];
    };

    const handleContinue = () => {
        navigate("/main-menu");
    };

    return (
        <div className="league-generation">
            <h1>Ligas Generadas</h1>
            {Object.keys(clasificacion).map((liga) => (
                <div key={liga}>
                    <h2>{liga}</h2>
                </div>
            ))}
            <button onClick={handleContinue}>Continuar</button>
            {equiposPendientes.length > 0 && (
    <div style={{ marginTop: "30px" }}>
        <h2>📌 Asignar equipos con grupo pendiente</h2>
        {equiposPendientes.map((equipo, idx) => (
            <div key={idx} style={{ marginBottom: "10px" }}>
                <strong>{equipo.nombre}</strong> ({equipo.liga})
                <select
                    style={{ marginLeft: "10px" }}
                    onChange={(e) => asignarEquipoAGrupo(equipo, e.target.value)}
                    defaultValue=""
                >
                    <option value="">Elige grupo</option>
                    {Object.keys(grupos).map((grupo, i) => (
                        <option key={i} value={grupo}>
                            {grupo} ({grupos[grupo].length} equipos)
                        </option>
                    ))}
                </select>
            </div>
        ))}
    </div>
)}
<button
    onClick={() => {
        const equiposFinales = [...equiposPendientes, ...Object.values(grupos).flat()];
        localStorage.setItem("equipos", JSON.stringify(equiposFinales));

        // Limpiar todo salvo equipos
        const soloEquipos = localStorage.getItem("equipos");
        localStorage.clear();
        localStorage.setItem("equipos", soloEquipos);
        localStorage.setItem("esLigaPrimera", JSON.stringify(true));

        // Redirigir a LeagueGeneration para reiniciar todo
        window.location.href = "/league-generation";
    }}
    style={{
        marginTop: "30px",
        padding: "12px 20px",
        fontWeight: "bold",
        backgroundColor: "#007bff",
        color: "white",
        border: "none",
        borderRadius: "6px",
        cursor: "pointer"
    }}
>
    ✅ Confirmar asignaciones y generar nuevas ligas
</button>
        </div>
    );
};

export default LeagueGeneration;
